(ns metabase.metabot.used-tables
  "Extract table references from queries generated by the tool calls in a metabot message.

  Walks `:tool-input` / `:tool-output` pairs, dispatches on tool name:
  - `construct_notebook_query` — query in `:structured-output.query`.
  - `create_sql_query` / `replace_sql_query` / `edit_sql_query` — native SQL.
  - `write_transform_sql` — native query in `:structured-output.transform.source.query`.
  - `write_transform_python` — table ids declared explicitly in the
    `:source_tables` tool-input argument.

  For both native and mbql queries, we recursively expand card references to extract underlying source tables.

  - Collects table and card ids via [[metabase.lib.core/all-referenced-entity-ids]]. The metadata provider is shared
    across the whole extraction via [[metabase.lib-be.core/with-metadata-provider-cache]].
  - All tool-call pairs in a single message feed into one shared BFS, so a card referenced from multiple pairs is
    resolved at most once per extraction. This matters for iterative-refinement patterns where the agent regenerates
    the same query shape and sources or template-tags the same upstream card on each pass.
  - Treats `:metric` refs as cards for recursion. Enqueueing their `:dataset_query` collapses metric references down
    to their underlying source tables alongside questions and models.
  - For native stages, runs the sql parser via [[metabase.metabot.query-analyzer/tables-for-native]] to recover
    tables inside raw SQL text.
  - Visited card ids are tracked to break cycles."
  (:require
   [clojure.set :as set]
   [metabase.analytics-interface.core :as analytics]
   [metabase.lib-be.core :as lib-be]
   [metabase.lib.core :as lib]
   [metabase.lib.metadata :as lib.metadata]
   [metabase.metabot.query-analyzer :as nqa]
   [metabase.metabot.tools :as metabot.tools]
   [metabase.util :as u]
   [metabase.util.log :as log]
   [toucan2.core :as t2])
  (:import
   (java.util.concurrent ArrayBlockingQueue Callable ExecutionException ExecutorService Future RejectedExecutionException ThreadFactory ThreadPoolExecutor TimeoutException TimeUnit)))

(set! *warn-on-reflection* true)

(defn- record-extraction-warning!
  "Increment the used-tables-extraction-warnings prometheus counter."
  [reason]
  (analytics/inc! :metabase-metabot/used-tables-extraction-warnings {:reason reason}))

(def ^:private notebook-tool-name "construct_notebook_query")
(def ^:private transform-sql-tool-name "write_transform_sql")
(def ^:private transform-python-tool-name "write_transform_python")

(def ^:private transform-tool-names
  #{transform-sql-tool-name transform-python-tool-name})

(def ^:private tracked-tool-names
  "Union of every tool name whose successful invocation we mine for table references. We keep the transform tools
  out of [[metabase.metabot.tools/query-generation-tool-names]] because the metabot_analytics module makes shape
  assumptions about that set (`:query-content`/`:database`/etc. in structured-output) that transform outputs do not
  satisfy."
  (into transform-tool-names metabot.tools/query-generation-tool-names))

(defn- tool-output->structured
  [result]
  (when (map? result)
    (or (:structured-output result)
        (:structured_output result))))

(defn- successful-tracked-output?
  "Is this a successful invocation of a tool in tracked-tool-names?"
  [input-block output-block]
  (and output-block
       (contains? tracked-tool-names (:function input-block))
       (not (:error output-block))
       (some? (tool-output->structured (:result output-block)))))

(defn- ->mbql5-query
  "Convert a raw query (legacy or MBQL 5) into an MBQL 5 query with `metadata-providerable` attached.
  Returns nil on conversion failure."
  [metadata-providerable raw-query]
  (try
    (lib/query metadata-providerable raw-query)
    (catch Exception e
      (record-extraction-warning! :query-build)
      (log/warn e "Failed to convert query to MBQL 5")
      (log/debugf "Failed to convert query to MBQL 5: %s" (pr-str raw-query))
      nil)))

(defn- native-tables
  "If `query` is native, run `tables-for-native` against it and return its underlying table ids."
  [query]
  (if (lib/native? query)
    (try
      (let [result (nqa/tables-for-native query)]
        (if (:error result)
          (do (record-extraction-warning! :native-parse)
              (log/warnf "tables-for-native error: %s" (:error result))
              (log/debugf "tables-for-native error: %s; query: %s" (:error result) (pr-str query))
              #{})
          (into #{} (keep :table-id) (:tables result))))
      (catch Exception e
        (record-extraction-warning! :native-parse)
        (log/warn e "Failed to extract tables from native SQL")
        (log/debugf "Failed to extract tables from native SQL: %s" (pr-str query))
        #{}))
    #{}))

(defn- query-tables-and-cards
  "Walk one query and return `{:tables #{table-id ...} :cards #{card-id ...}}`.

  `:tables` includes `:source-table` ids, template-tag table ids, the parent tables of implicitly-joined field refs,
  and any tables found by `native-tables`.

  `:cards` includes `:source-card`, template-tag `:card-id`, and `:metric` ref ids."
  [query]
  (try
    (let [ids (lib/all-referenced-entity-ids [query])]
      {:tables (set/union (:table ids)
                          (native-tables query))
       :cards  (set/union (:card ids) (:metric ids))})
    (catch Exception e
      (record-extraction-warning! :query-walk)
      (log/warn e "Failed to walk query for used-table extraction")
      (log/debugf "Failed to walk query for used-table extraction: %s" (pr-str query))
      {:tables #{} :cards #{}})))

(defn- card-query
  "Look up the Card with `card-id` via `metadata-providerable` and return its underlying query. Warns and returns
  nil if the card is missing or the conversion fails."
  [metadata-providerable card-id]
  (try
    (if-let [card (lib.metadata/card metadata-providerable card-id)]
      (lib/card->underlying-query metadata-providerable card)
      (do (record-extraction-warning! :card-missing)
          (log/warnf "Card %s referenced by Metabot query was not found" card-id)
          nil))
    (catch Exception e
      (record-extraction-warning! :card-lookup)
      (log/warnf e "Failed to look up card %s for used-table extraction" card-id)
      nil)))

(defn- collect-tables
  "BFS over a queue of MBQL queries, accumulating referenced table ids.

  Tracks visited card ids to break cycles and to skip redundant work when the same card is referenced from multiple
  seed queries.

  Called once per [[extract-used-tables]] invocation with seed queries gathered from every tool-call pair, so the
  `visited` set is shared across pairs."
  [initial-queries]
  (loop [tables  #{}
         queue   (vec initial-queries)
         visited #{}]
    (if (empty? queue)
      tables
      (let [query                  (first queue)
            queue'                 (subvec queue 1)
            {ts :tables cs :cards} (query-tables-and-cards query)
            new-cards              (set/difference cs visited)
            new-queries            (keep #(card-query query %) new-cards)]
        (recur (into tables ts)
               (into queue' new-queries)
               (into visited new-cards))))))

(defn- notebook-starting-query
  "Starting query for a `construct_notebook_query` tool output."
  [metadata-providerable structured]
  (some->> (:query structured)
           (->mbql5-query metadata-providerable)))

(defn- sql-raw-text
  "Best-effort raw SQL text for a SQL tool call."
  [tool-name arguments structured]
  (or (:query-content structured)
      (case tool-name
        "create_sql_query"  (:sql_query arguments)
        "replace_sql_query" (:new_query arguments)
        nil)))

(defn- sql-starting-query
  "Starting query for an SQL tool output.
  Prefers the structured output's full `:query` map; falls back to building a native query from the structured
  output's `:database` field plus the tool's raw SQL text."
  [metadata-providerable tool-name arguments structured]
  (or (notebook-starting-query metadata-providerable structured)
      (when-let [db-id (:database structured)]
        (when-let [sql (sql-raw-text tool-name arguments structured)]
          (when (seq sql)
            (try
              (lib/native-query (lib.metadata/->metadata-provider metadata-providerable db-id) sql)
              (catch Exception e
                (record-extraction-warning! :native-build)
                (log/warnf e "Failed to build native query for %s from raw SQL on database %s" tool-name db-id)
                (log/debugf "Failed to build native query for %s from raw SQL on database %s: %s" tool-name db-id sql)
                nil)))))))

(defn- transform-sql-starting-query
  "Starting query for a `write_transform_sql` tool output."
  [metadata-providerable structured]
  (some->> (get-in structured [:transform :source :query])
           (->mbql5-query metadata-providerable)))

(defn- transform-declared-table-ids
  "Read `:table_id` values from a `write_transform_*` tool's `:source_tables` argument.
  Required by the Python tool's schema; absent from the SQL tool's schema."
  [arguments]
  (into #{} (keep :table_id) (:source_tables arguments)))

(def ^:private empty-seeds {:queries [] :tables #{}})

(defn- pair->seeds
  "Return `{:queries [...] :tables #{...}}` for one `(tool-input, tool-output)` pair.

  `:queries` are MBQL queries to feed into the shared BFS in [[extract-used-tables]].

  `:tables` are already-known table ids. Currently only populated by the Python transform tool, which declares its
  sources in the `:source_tables` argument rather than embedding them in a query."
  [metadata-providerable input-block output-block]
  (let [tool-name  (:function input-block)
        arguments  (:arguments input-block)
        structured (tool-output->structured (:result output-block))]
    (cond
      (= tool-name notebook-tool-name)
      (if-let [start (notebook-starting-query metadata-providerable structured)]
        {:queries [start] :tables #{}}
        empty-seeds)

      (= tool-name transform-sql-tool-name)
      {:queries (if-let [start (transform-sql-starting-query metadata-providerable structured)]
                  [start]
                  [])
       :tables  (transform-declared-table-ids arguments)}

      (= tool-name transform-python-tool-name)
      {:queries [] :tables (transform-declared-table-ids arguments)}

      :else
      (if-let [start (sql-starting-query metadata-providerable tool-name arguments structured)]
        {:queries [start] :tables #{}}
        empty-seeds))))

(defn- ->rows
  [message-id table-ids]
  (mapv (fn [id] {:message_id message-id :table_id id})
        table-ids))

(defn- extract-used-tables
  "Walk the `parts` vector and return rows for `metabot_used_table`.

  One row per distinct `(message-id, table-id)` pair. Returns `[]` when nothing was referenced.

  Runs a single BFS across all tool-call pairs, so a card referenced from multiple pairs is resolved at most once per
  call.

  Must run on the pre-strip `parts` before [[metabase.metabot.persistence/strip-tool-output-bloat]] trims tool-output;
  the transform path needs the un-trimmed `:transform` key, which is not
  in [[metabase.metabot.persistence/persisted-structured-output-keys]]."
  ([message-id parts]
   (lib-be/with-metadata-provider-cache
     (extract-used-tables lib-be/application-database-metadata-provider message-id parts)))
  ([metadata-providerable message-id parts]
   (let [outputs-by-id (into {}
                             (comp (filter #(= :tool-output (:type %)))
                                   (map (juxt :id identity)))
                             parts)
         pairs         (into []
                             (comp (filter #(= :tool-input (:type %)))
                                   (keep (fn [input]
                                           (let [output (get outputs-by-id (:id input))]
                                             (when (successful-tracked-output? input output)
                                               [input output])))))
                             parts)
         {:keys [queries tables]}
         (reduce (fn [acc [input output]]
                   (let [seeds (pair->seeds metadata-providerable input output)]
                     (-> acc
                         (update :queries into (:queries seeds))
                         (update :tables into (:tables seeds)))))
                 empty-seeds
                 pairs)
         all-tables (into tables (collect-tables queries))]
     (->rows message-id all-tables))))

(def ^:dynamic *run-synchronously?*
  "When true, [[record-used-tables!]] extracts and inserts on the calling thread instead of the background
  executor. Bound to true in tests so assertions can read `metabot_used_table` rows immediately after a turn is
  finalized, and so the work participates in the test's rollback transaction."
  false)

(def ^:private extraction-timeout-ms
  "Hard cap on a single used-table extraction. On timeout we abandon the work and persist no rows for the message.
  This is safeguard against bugs or pathological queries. Under normal circumstances, even for large queries,
  extraction should not take more than a few seconds."
  (* 15 1000))

(def ^:private executor-queue-capacity
  "Max number of tasks allowed to sit in either pool's queue. Beyond this, new submissions are rejected.
  256 caps worst-case retained heap in the low hundreds of MiB; the intention is that the queues are normally
  ~empty (extraction is far faster than turns arrive), and this only kicks in under a regression/stall/abuse."
  256)

(def ^:private pool-size
  "Max threads in each of [[waiter-executor]] and [[worker-executor]]. Caps concurrent extractions:
  every [[waiter-executor]] has a matching [[worker-executor]]. Threads are created on demand and reaped
  after [[idle-timeout-ms]]."
  4)

(def ^:private idle-timeout-ms
  "How long an idle thread lives before being reaped. With `allowCoreThreadTimeOut`, this applies to every thread,
  so a pool that has been idle this long scales back down to zero threads."
  (* 5 60 1000))

(defn- thread-pool-executor
  "Pool of up to [[pool-size]] daemon threads named `thread-name`, created on demand.

  Backed by a bounded queue of [[executor-queue-capacity]]. The default `AbortPolicy` throws
  `RejectedExecutionException` once the queue is full. Idle threads are reaped after [[idle-timeout-ms]]."
  ^ThreadPoolExecutor [thread-name]
  (doto (ThreadPoolExecutor.
         (int pool-size)
         (int pool-size)
         (long idle-timeout-ms) TimeUnit/MILLISECONDS
         (ArrayBlockingQueue. (int executor-queue-capacity))
         (reify ThreadFactory
           (newThread [_ r]
             (doto (Thread. r)
               (.setName thread-name)
               (.setDaemon true)))))
    (.allowCoreThreadTimeOut true)))

(defonce ^:private waiter-executor
  ;; Outer pool: runs the `extract-and-insert!` tasks submitted by `record-used-tables!`. Each task blocks waiting
  ;; (with a timeout) on the result of an extraction submitted to `worker-executor`. Bounding this pool caps how many
  ;; turns we process concurrently; the bounded queue caps how many pending requests we retain. The default
  ;; `AbortPolicy` rejects beyond that, which `record-used-tables!` catches to drop the task. Keeping the work on
  ;; these bounded pools (rather than `u/with-timeout`'s unbounded shared `future` pool) means a stall can't spill
  ;; onto threads shared with the rest of the app.
  (delay (thread-pool-executor "metabot-used-tables-waiter")))

(defonce ^:private worker-executor
  ;; Inner pool: runs the (usually fast, but potentially slow) BFS+sql parse. Kept separate from `waiter-executor` so
  ;; a burst of waiters can never starve the workers doing the extractions. Sized to match `waiter-executor` so every
  ;; waiter has a worker. Rows are keyed by distinct `message_id`, so concurrent inserts don't contend.
  (delay (thread-pool-executor "metabot-used-tables-worker")))

(defn- extract-used-tables-async-with-timeout
  "Run [[extract-used-tables]] on [[worker-executor]] and block the calling [[waiter-executor]] thread on the result for
  up to [[extraction-timeout-ms]]. On timeout the work is cancelled and a `TimeoutException` is thrown. Any extraction
  failure is unwrapped from its `ExecutionException` and rethrown."
  [message-id parts]
  (let [fut ^Future (.submit ^ExecutorService @worker-executor
                             ^Callable (bound-fn* #(extract-used-tables message-id parts)))]
    (try
      (.get fut extraction-timeout-ms TimeUnit/MILLISECONDS)
      (catch ExecutionException e
        (throw (.getCause e)))
      (catch TimeoutException e
        (.cancel fut true)
        (throw e)))))

(defn- extract-used-tables-with-timing!
  "Like the 2-arity [[extract-used-tables]] but records Prometheus timing/failure metrics and caps runtime at
  [[extraction-timeout-ms]]. Returns nil (persisting no rows) and counts a timeout if the cap is exceeded.

  When not running synchronously the work is handed off via [[extract-used-tables-async-with-timeout]]. The
  timeout/handoff is skipped when [[*run-synchronously?*]] is set (tests), so extraction stays on the calling thread
  and inside the test transaction."
  [message-id parts]
  (let [start (u/start-timer)]
    (analytics/inc! :metabase-metabot/used-tables-extraction-total)
    (try
      (let [result (if *run-synchronously?*
                     (extract-used-tables message-id parts)
                     (extract-used-tables-async-with-timeout message-id parts))]
        (analytics/observe! :metabase-metabot/used-tables-extraction-duration-ms (long (u/since-ms start)))
        result)
      (catch TimeoutException _
        (analytics/inc! :metabase-metabot/used-tables-extraction-timeouts)
        (analytics/observe! :metabase-metabot/used-tables-extraction-duration-ms (long (u/since-ms start)))
        (log/warnf "Used-table extraction for message %s exceeded the %sms timeout; abandoning extraction"
                   message-id extraction-timeout-ms)
        nil)
      (catch Throwable t
        (analytics/inc! :metabase-metabot/used-tables-extraction-errors)
        (analytics/observe! :metabase-metabot/used-tables-extraction-duration-ms (long (u/since-ms start)))
        (throw t)))))

(defn- extract-and-insert!
  "Extract used tables from `parts` and insert `metabot_used_table` rows for `message-id`.
  Best-effort: any `Exception` (extraction *or* insert) is logged and swallowed, since this runs
  off the turn-finalization path and must never surface to the user. For example, a table
  deleted between query generation and now would make the row's `table_id` FK invalid."
  [message-id parts]
  (log/with-thread-context {:metabot_message_id message-id}
    (try
      (let [rows (extract-used-tables-with-timing! message-id parts)]
        (when (seq rows)
          (t2/insert! :model/MetabotUsedTable rows)))
      (catch Exception e
        (log/warn e "Failed to record metabot used tables for message" message-id)))))

(defn record-used-tables!
  "Extract used tables from `parts` and persist `metabot_used_table` rows for `message-id`.

  The extraction can be slow for large native queries, so by default this is handed off to a background
  [[waiter-executor]] and returns immediately. Callers must already have committed the message row so the
  `message_id` FK is valid.

  When the background executor's bounded queue is full, the task is dropped (logged + counted), rather than blocking
  turn finalization or growing the queue without bound.

  Binding [[*run-synchronously?*]] true runs the work inline on the calling thread instead (used in tests)."
  [message-id parts]
  (if *run-synchronously?*
    (extract-and-insert! message-id parts)
    (try
      (.submit ^ExecutorService @waiter-executor
               ^Callable (bound-fn* #(extract-and-insert! message-id parts)))
      (catch RejectedExecutionException _
        (analytics/inc! :metabase-metabot/used-tables-extraction-dropped)
        (log/warnf "used-tables extraction queue full (capacity %d); dropping extraction for message %s"
                   executor-queue-capacity message-id)))))
